    public static function menu(): void { add_submenu_page('elev8-os','Gallery Operations','Gallery Operations','manage_options','elev8-gallery-operations',[__CLASS__,'render']); }
    public static function assets(string $hook): void { if($hook!=='elev8-os_page_elev8-gallery-operations') return; wp_enqueue_style('elev8-gallery-operations',ELEV8_OS_URL.'assets/css/gallery-operations.css',[],ELEV8_OS_VERSION); }
    public static function render(): void {
        if(!current_user_can('manage_options')) wp_die('Not allowed.');
        $artist_filter=absint($_GET['artist_filter']??0); $view=sanitize_key((string)($_GET['view']??'dashboard')); $search=sanitize_text_field((string)($_GET['art_search']??''));
        $d=Elev8_OS_Gallery_Operations_Service::dashboard($artist_filter,$search); $zones=Elev8_OS_Gallery_Operations_Service::get_selectable_zones(); $counts=[]; foreach($d['zones'] as $zone_summary){$counts[absint($zone_summary['id'])]=$zone_summary;} foreach($zones as &$zone){$summary=$counts[absint($zone['id'])]??[];$zone['piece_count']=absint($summary['piece_count']??0);$zone['display_value']=(float)($summary['display_value']??0);} unset($zone); $notice=sanitize_text_field((string)($_GET['gallery_notice']??'')); ?>
        <div class="wrap elev8-gallery-ops"><header class="elev8-go-header"><div><p class="eyebrow">ELEV8 OS 9.0.7</p><h1>Gallery Operations</h1><p>Place, move, store, and find every artwork from one screen.</p></div><span class="mode-pill">Gallery Mode</span></header>
        <?php if($notice):?><div class="notice notice-success is-dismissible"><p><?php echo esc_html($notice);?></p></div><?php endif;?>
